function solve(nums, k) {
    let prefixSum = 0;
    const modMap = new Map();
    modMap.set(0, -1);
    const n = nums.length;
    const dp = new Array(n + 1).fill(0);
    let sum = 0;

    for (let i = 0; i < n; i++) {
        prefixSum += nums[i];
        const mod = ((prefixSum % k) + k) % k;
        if (modMap.has(mod)) {
            const prevIndex = modMap.get(mod);
            dp[i + 1] = Math.max(dp[i], dp[prevIndex + 1] + prefixSum - (prevIndex === -1 ? 0 : dp[prevIndex + 1]));
        } else {
            dp[i + 1] = dp[i];
        }
        modMap.set(mod, i);
        sum += nums[i];
    }

    return sum - dp[n];
}
```

